+#[cfg(test)]
+mod tests {
+    use super::*;
+    use ftui_core::event::{KeyEventKind, Modifiers};
+
+    fn press(code: KeyCode) -> KeyEvent {
+        KeyEvent {
+            code,
+            modifiers: Modifiers::NONE,
+            kind: KeyEventKind::Press,
+        }
+    }
+
+    fn new_state() -> MermaidShowcaseState {
+        MermaidShowcaseState::new()
